// Credit Recovery — Form client script.
// Installed as a Client Script record (dt: Credit Recovery, view: Form).
// Days Outstanding is also enforced server-side (Before Save server script), so
// this client calculation is for instant feedback only.

frappe.ui.form.on('Credit Recovery', {
    refresh(frm) {
        const is_admin = frappe.session.user === 'Administrator'
            || frappe.user.has_role('System Manager');

        if (frm.doc.recovery_status === 'Paid' && !frm.is_new() && !is_admin) {
            frm.disable_form();
            frm.set_intro(
                __('This record is marked Paid and is locked. Contact an administrator to make changes.'),
                'orange'
            );
        }

        if (!frm.is_new()) {
            frm.add_custom_button(__('Create Follow-up ToDo'), () => create_followup_todo(frm));
        }

        if (frm.doc.credit_limit && frm.doc.outstanding_amount > frm.doc.credit_limit) {
            frm.dashboard.set_headline(
                __('Outstanding exceeds credit limit by {0}',
                    [format_currency(frm.doc.outstanding_amount - frm.doc.credit_limit)])
            );
        }
    },

    oldest_invoice_date(frm) {
        set_days_outstanding(frm);
    },

    promised_payment_date(frm) {
        // Convenience: a promise usually implies the next follow-up.
        if (frm.doc.promised_payment_date && !frm.doc.next_follow_up_date) {
            frm.set_value('next_follow_up_date', frm.doc.promised_payment_date);
        }
    },
});

function set_days_outstanding(frm) {
    if (frm.doc.oldest_invoice_date) {
        frm.set_value('days_outstanding',
            frappe.datetime.get_day_diff(frappe.datetime.get_today(), frm.doc.oldest_invoice_date));
    } else {
        frm.set_value('days_outstanding', 0);
    }
}

function create_followup_todo(frm) {
    const priority_map = { Critical: 'High', High: 'High', Medium: 'Medium', Low: 'Low' };
    frappe.call({
        method: 'frappe.client.insert',
        freeze: true,
        freeze_message: __('Creating ToDo...'),
        args: {
            doc: {
                doctype: 'ToDo',
                allocated_to: frm.doc.assigned_to || frappe.session.user,
                reference_type: 'Credit Recovery',
                reference_name: frm.doc.name,
                date: frm.doc.next_follow_up_date || frappe.datetime.get_today(),
                priority: priority_map[frm.doc.priority] || 'Medium',
                description: __('Credit recovery follow-up: {0} — outstanding {1}',
                    [frm.doc.customer, format_currency(frm.doc.outstanding_amount || 0)]),
            },
        },
        callback(r) {
            if (!r.exc && r.message) {
                frappe.show_alert({
                    message: __('Follow-up ToDo {0} created',
                        [`<a href="/app/todo/${r.message.name}">${r.message.name}</a>`]),
                    indicator: 'green',
                });
            }
        },
    });
}

// Credit Recovery — List view client script.
// Installed as a Client Script record (dt: Credit Recovery, view: List).
// Provides the status indicator colors and the four quick filters as a
// "Quick Filters" button group. Buttons compute dates at click time, so
// "Due Today" / "Overdue" are always relative to the actual current date
// (saved static filters cannot do this).

frappe.listview_settings['Credit Recovery'] = {
    add_fields: ['recovery_status', 'priority', 'next_follow_up_date', 'outstanding_amount'],

    get_indicator(doc) {
        const colors = {
            'Paid': 'green',
            'Payment Promised': 'yellow',
            'Contacted': 'orange',
            'Escalated': 'red',
            'Current': 'blue',
            'Reminder Due': 'purple',
            'Partial Payment': 'cyan',
            'Dispute': 'grey',
        };
        return [
            __(doc.recovery_status),
            colors[doc.recovery_status] || 'grey',
            'recovery_status,=,' + doc.recovery_status,
        ];
    },

    onload(listview) {
        const apply_filters = async (filters) => {
            await listview.filter_area.clear();
            await listview.filter_area.add(filters);
        };
        const group = __('Quick Filters');

        listview.page.add_inner_button(__('Due Today'), () => apply_filters([
            ['Credit Recovery', 'next_follow_up_date', '=', frappe.datetime.get_today()],
            ['Credit Recovery', 'recovery_status', '!=', 'Paid'],
        ]), group);

        listview.page.add_inner_button(__('Overdue Follow-ups'), () => apply_filters([
            ['Credit Recovery', 'next_follow_up_date', '<', frappe.datetime.get_today()],
            ['Credit Recovery', 'recovery_status', '!=', 'Paid'],
        ]), group);

        listview.page.add_inner_button(__('Critical Accounts'), () => apply_filters([
            ['Credit Recovery', 'priority', '=', 'Critical'],
            ['Credit Recovery', 'recovery_status', '!=', 'Paid'],
        ]), group);

        listview.page.add_inner_button(__('Promised Payments'), () => apply_filters([
            ['Credit Recovery', 'recovery_status', '=', 'Payment Promised'],
        ]), group);
    },
};

frappe.ui.form.on('Item', {
    refresh: function(frm){ pd_set_template(frm); pd_fetch_molecule(frm); },
    item_group: function(frm){ pd_set_template(frm); },
    pd_pesticide_technical_name: function(frm){ pd_fetch_molecule(frm); }
});
function pd_set_template(frm){
    if(!frm.doc.item_group){ return; }
    frappe.db.get_value('Item Group', frm.doc.item_group, 'product_detail_template').then(function(r){
        var t = (r.message || {}).product_detail_template || '';
        if(frm.doc.product_detail_template !== t){
            frm.doc.product_detail_template = t;
            frm.refresh_field('product_detail_template');
            frm.refresh_fields();
        }
    });
}
function pd_fetch_molecule(frm){
    var tn = frm.doc.pd_pesticide_technical_name;
    if(!tn){ frm.doc.pd_tn_pests=''; frm.doc.pd_tn_crops='';
             frm.refresh_field('pd_tn_pests'); frm.refresh_field('pd_tn_crops'); return; }
    frappe.db.get_doc('Technical Name', tn).then(function(doc){
        frm.doc.pd_tn_pests = (doc.pests_covered || []).map(function(r){return r.pest;}).join(', ');
        frm.doc.pd_tn_crops = (doc.crops_covered || []).map(function(r){return r.crop;}).join(', ');
        frm.refresh_field('pd_tn_pests'); frm.refresh_field('pd_tn_crops');
    });
}
